async (params, browser) => {
  // Open Notion
  await browser.open('https://www.notion.so')

  // Wait for sidebar
  await browser.waitForSelector('.notion-sidebar, .notion-scroller', 15000)

  // Let sidebar render
  await browser.wait(3000)

  // Extract sidebar pages
  const result = await browser.evaluate(`const pages = []; const items = document.querySelectorAll('.notion-sidebar .notion-sidebar-container [data-block-id], .notion-sidebar a[href*="notion.so"]'); for (let i = 0; i < Math.min(items.length, 30); i++) { const item = items[i]; const titleEl = item.querySelector('.notranslate, [data-content-editable-leaf], span'); const title = titleEl?.textContent?.trim() || item.textContent?.trim() || ''; const blockId = item.getAttribute('data-block-id') || ''; const href = item.getAttribute('href') || ''; if (title && title.length > 1) { pages.push({ title: title.substring(0, 100), id: blockId, url: href || (blockId ? 'https://www.notion.so/' + blockId.replace(/-/g, '') : '') }); } } return { result_count: pages.length, pages: pages }`)

  return result
}
